import React, { useState } from "react";
import { useDispatch } from "react-redux";
import { updateQuantity } from "../../app/cartSlice";
import styles from "./product-info.module.css";
import Title from "../../title";
import Quantity from "../quantity";
import Subscription from "../subscription";
import ButtonAdd from "../../button-add";
import Details from "../details";

interface InfoProps {
  product: {
    id: number;
    img: string;
    name: string;
    price: number;
  };
}

const ProductInfo: React.FC<InfoProps> = ({ product }) => {
  const [quantity, setQuantity] = useState(1); // Local quantity state
  const dispatch = useDispatch(); // Get the dispatch function from Redux

  const handleQuantityChange = (newQuantity: number) => {
    setQuantity(newQuantity);
    // Dispatch an action to update the quantity in Redux store
    dispatch(updateQuantity({ id: product.id, quantity: newQuantity }));
  };

  return (
    <div className={styles.wrapper_product_info}>
      <Title level="h3" className={styles.title}>
        {product.name} Candleaf®
      </Title>
      <div className={styles.container_inner}>
        <div className={styles.container_left}>
          <span className={styles.price}>${product.price}</span>
          <div className={styles.wrapper_quantity}>
            <h6 className={styles.quantity_title}>Quantity</h6>
            {/* Pass local quantity and handler to Quantity component */}
            <Quantity itemId={product.id} quantity={quantity} onQuantityChange={handleQuantityChange} />
          </div>
        </div>
        <div className={styles.container_right}>
          <Subscription />
          <ButtonAdd product={product} />
        </div>
      </div>
      <Details />
    </div>
  );
};

export default ProductInfo;






